    94→	sort.Strings(r.PolicyRule.Resources)
    95→	sort.Strings(r.PolicyRule.ResourceNames)
    96→	sort.Strings(r.PolicyRule.APIGroups)
    97→	sort.Strings(r.PolicyRule.NonResourceURLs)
