   122→// NewRule returns new PolicyRule made by input verbs.
   123→func NewRule(verbs ...string) *PolicyRuleBuilder {
   124→	return &PolicyRuleBuilder{
   125→		PolicyRule: PolicyRule{Verbs: sets.NewString(verbs...).List()},
   126→	}
   127→}
