   258→// BindingOrDie calls the binding method and panics if there is an error.
   259→func (r *ClusterRoleBindingBuilder) BindingOrDie() ClusterRoleBinding {
   260→	ret, err := r.Binding()
   261→	if err != nil {
   262→		panic(err)
   263→	}
   264→	return ret
   265→}
