   267→// Binding builds and returns the ClusterRoleBinding API object from the builder
   268→// object.
   269→func (r *ClusterRoleBindingBuilder) Binding() (ClusterRoleBinding, error) {
   270→	if len(r.ClusterRoleBinding.Subjects) == 0 {
